"use client";

import { useMemo, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import type { TeachingDataset } from "@/lib/lesson-data";
import {
  SCATTER_PURPOSES,
  SCATTERPURPOSE_INTRO,
  buildScatterFromTeaching,
  type ScatterPurposeId,
  type ScatterPoint,
  type ScatterAxes,
} from "@/lib/scatterplot-purposes";
import { TermButton } from "@/components/glossary/TermButton";

const CLUSTER_COLORS = ["#FF2D6B", "#0066FF", "#FFE600", "#00E5A0"];

type Props = {
  data: TeachingDataset;
  accent?: string;
};

function ScatterDisplay({
  purpose,
  points,
  axes,
  accent,
}: {
  purpose: ScatterPurposeId;
  points: ScatterPoint[];
  axes: ScatterAxes;
  accent: string;
}) {
  const w = 340;
  const h = 260;
  const pad = 44;
  const innerW = w - pad * 2;
  const innerH = h - pad * 2;

  const xMin = 0.5;
  const xMax = 5.5;
  const yMin = 0.5;
  const yMax = 5.5;

  const xAt = (v: number) => pad + ((v - xMin) / (xMax - xMin)) * innerW;
  const yAt = (v: number) => pad + innerH - ((v - yMin) / (yMax - yMin)) * innerH;

  const trend = useMemo(() => {
    const n = points.length;
    const mx = points.reduce((s, p) => s + p.x, 0) / n;
    const my = points.reduce((s, p) => s + p.y, 0) / n;
    let num = 0;
    let den = 0;
    for (const p of points) {
      num += (p.x - mx) * (p.y - my);
      den += (p.x - mx) ** 2;
    }
    const slope = den === 0 ? 0 : num / den;
    const intercept = my - slope * mx;
    const x1 = xMin;
    const x2 = xMax;
    return { x1, y1: slope * x1 + intercept, x2, y2: slope * x2 + intercept };
  }, [points]);

  const clusterStats = useMemo(() => {
    const map = new Map<number, ScatterPoint[]>();
    for (const p of points) {
      const list = map.get(p.cluster) ?? [];
      list.push(p);
      map.set(p.cluster, list);
    }
    return [...map.entries()].map(([ci, pts]) => {
      const mx = pts.reduce((s, p) => s + p.x, 0) / pts.length;
      const my = pts.reduce((s, p) => s + p.y, 0) / pts.length;
      const rx = Math.max(...pts.map((p) => Math.abs(p.x - mx))) + 0.35;
      const ry = Math.max(...pts.map((p) => Math.abs(p.y - my))) + 0.35;
      return { ci, mx, my, rx, ry };
    });
  }, [points]);

  return (
    <div className="overflow-x-auto">
      <svg viewBox={`0 0 ${w} ${h}`} className="w-full max-w-md border-2 border-black bg-white">
        {[1, 2, 3, 4, 5].map((tick) => (
          <g key={tick}>
            <line
              x1={pad}
              y1={yAt(tick)}
              x2={w - pad}
              y2={yAt(tick)}
              stroke="#EEE"
              strokeWidth={1}
            />
            <line
              x1={xAt(tick)}
              y1={pad}
              x2={xAt(tick)}
              y2={h - pad}
              stroke="#EEE"
              strokeWidth={1}
            />
            <text x={pad - 6} y={yAt(tick) + 3} textAnchor="end" fontSize={8} fill="#888">
              {tick}
            </text>
            <text x={xAt(tick)} y={h - pad + 14} textAnchor="middle" fontSize={8} fill="#888">
              {tick}
            </text>
          </g>
        ))}

        <text x={w / 2} y={h - 6} textAnchor="middle" fontSize={10} fontWeight={700}>
          {axes.xLabel}
        </text>
        <text
          x={12}
          y={h / 2}
          textAnchor="middle"
          fontSize={10}
          fontWeight={700}
          transform={`rotate(-90 12 ${h / 2})`}
        >
          {axes.yLabel}
        </text>

        {purpose === "correlation" && (
          <motion.line
            x1={xAt(trend.x1)}
            y1={yAt(trend.y1)}
            x2={xAt(trend.x2)}
            y2={yAt(trend.y2)}
            stroke={accent}
            strokeWidth={2.5}
            strokeDasharray="6 4"
            initial={{ pathLength: 0, opacity: 0 }}
            animate={{ pathLength: 1, opacity: 0.85 }}
            transition={{ duration: 0.8, delay: 0.3 }}
          />
        )}

        {purpose === "clusters" &&
          clusterStats.map(({ ci, mx, my, rx, ry }) => (
            <motion.ellipse
              key={ci}
              cx={xAt(mx)}
              cy={yAt(my)}
              rx={rx * (innerW / (xMax - xMin))}
              ry={ry * (innerH / (yMax - yMin))}
              fill={CLUSTER_COLORS[ci % CLUSTER_COLORS.length]}
              fillOpacity={0.12}
              stroke={CLUSTER_COLORS[ci % CLUSTER_COLORS.length]}
              strokeWidth={2}
              strokeDasharray="4 3"
              initial={{ scale: 0, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ delay: 0.2 + ci * 0.15, type: "spring" }}
            />
          ))}

        {purpose === "distribution" &&
          clusterStats.map(({ ci, mx, my, rx, ry }) => (
            <g key={ci}>
              <motion.rect
                x={xAt(mx - rx)}
                y={yAt(my + ry)}
                width={rx * 2 * (innerW / (xMax - xMin))}
                height={ry * 2 * (innerH / (yMax - yMin))}
                fill="none"
                stroke="#0A0A0A"
                strokeWidth={1.5}
                strokeOpacity={0.35}
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.25 + ci * 0.12 }}
              />
            </g>
          ))}

        {points.map((p, i) => {
          const color = CLUSTER_COLORS[p.cluster % CLUSTER_COLORS.length];
          const isOutlier = purpose === "outliers" && p.outlier;
          const dim = purpose === "outliers" && !p.outlier;
          const showLabel = purpose !== "distribution" || p.outlier;

          return (
            <g key={p.id}>
              {isOutlier && (
                <motion.circle
                  cx={xAt(p.x)}
                  cy={yAt(p.y)}
                  r={16}
                  fill="none"
                  stroke="#FF0040"
                  strokeWidth={2}
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: [1, 1.2, 1], opacity: 0.7 }}
                  transition={{ repeat: Infinity, duration: 1.6, delay: 0.4 }}
                />
              )}
              <motion.circle
                cx={xAt(p.x)}
                cy={yAt(p.y)}
                r={isOutlier ? 8 : purpose === "clusters" ? 7 : 6}
                fill={purpose === "correlation" ? accent : color}
                stroke="#000"
                strokeWidth={2}
                initial={{ scale: 0, opacity: 0 }}
                animate={{ scale: 1, opacity: dim ? 0.3 : 1 }}
                transition={{ delay: 0.1 + i * 0.1, type: "spring", stiffness: 260 }}
              />
              {showLabel && (
                <motion.text
                  x={xAt(p.x)}
                  y={yAt(p.y) - 12}
                  textAnchor="middle"
                  fontSize={9}
                  fontWeight={700}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: dim ? 0.35 : 1 }}
                  transition={{ delay: 0.2 + i * 0.1 }}
                >
                  {p.id}
                </motion.text>
              )}
            </g>
          );
        })}
      </svg>
      <p className="mt-2 text-center text-xs text-[#888]">
        {axes.xHint} → x · {axes.yHint} → y
      </p>
    </div>
  );
}

export function ScatterplotPurposesPanel({ data, accent = "#9B5DE5" }: Props) {
  const [active, setActive] = useState<ScatterPurposeId>("correlation");
  const { points, axes } = useMemo(() => buildScatterFromTeaching(data), [data]);
  const purpose = SCATTER_PURPOSES.find((p) => p.id === active)!;

  return (
    <div className="space-y-5">
      <div className="border-2 border-black bg-[#F3EEFF] p-4 md:p-5">
        <p className="text-xs font-bold uppercase tracking-wide text-[#888]">Scatterplots</p>
        <p className="readable mt-2 text-[15px] text-[#333]">{SCATTERPURPOSE_INTRO}</p>
      </div>

      <div>
        <p className="text-xs font-semibold text-[#5c5c5c]">Four purposes</p>
        <div className="mt-2 grid grid-cols-2 gap-2">
          {SCATTER_PURPOSES.map((p) => {
            const selected = active === p.id;
            return (
              <motion.button
                key={p.id}
                layout
                onClick={() => setActive(p.id)}
                className="border-2 border-black px-3 py-2.5 text-left text-sm font-bold"
                style={{
                  backgroundColor: selected ? accent : "#FFF",
                  color: "#0A0A0A",
                }}
                whileTap={{ scale: 0.98 }}
              >
                <span className="block">{p.title}</span>
                <span className="block text-[11px] font-normal opacity-70">{p.subtitle}</span>
              </motion.button>
            );
          })}
        </div>
      </div>

      <AnimatePresence mode="wait">
        <motion.div
          key={active}
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -8 }}
          transition={{ duration: 0.25 }}
          className="space-y-4"
        >
          <div className="border-2 border-black bg-white p-4 md:p-5">
            <p className="text-xs font-bold uppercase tracking-wide text-[#888]">1 · Describe</p>
            <p className="mt-2 text-base font-bold">
              <TermButton termId={purpose.termId}>{purpose.title}</TermButton>
            </p>
            <p className="readable mt-2 text-[15px] text-[#333]">{purpose.description}</p>
          </div>

          <div className="border-2 border-black bg-[#FAFAFA] p-4 md:p-5">
            <p className="text-xs font-bold uppercase tracking-wide text-[#888]">2 · Display</p>
            <p className="readable mt-2 text-sm text-[#555]">
              {active === "outliers" && points.find((p) => p.outlier)
                ? `${points.find((p) => p.outlier)!.id} deviates from its cluster — ${purpose.displayCaption}`
                : purpose.displayCaption}
            </p>
            <div className="mt-4 flex justify-center">
              <ScatterDisplay
                purpose={active}
                points={points}
                axes={axes}
                accent={data.theme.accent}
              />
            </div>
          </div>
        </motion.div>
      </AnimatePresence>
    </div>
  );
}
